// Stateless async-job token codec — the contract behind POST /api/md/batch
// `Prefer: respond-async` → 202 → GET /api/jobs/{token}.

import { describe, expect, it } from "vitest";
import { decodeJobToken, encodeJobToken } from "@/lib/job-token";

describe("job token codec", () => {
	it("round-trips a batch spec", () => {
		const spec: import("@/lib/job-token").JobSpec = {
			v: 1,
			kind: "md-batch",
			paths: ["/docs/getting-started/installation", "/docs/hooks/overview"],
		};
		const token = encodeJobToken(spec);
		expect(token).toMatch(/^[A-Za-z0-9_-]+$/);
		expect(decodeJobToken(token)).toEqual(spec);
	});

	it("rejects garbage, wrong shapes, and oversized tokens", () => {
		expect(decodeJobToken("")).toBeNull();
		expect(decodeJobToken("not!base64url")).toBeNull();
		expect(decodeJobToken(Buffer.from("[1,2]").toString("base64url"))).toBeNull();
		expect(
			decodeJobToken(Buffer.from('{"v":2,"kind":"md-batch","paths":["/x"]}').toString("base64url")),
		).toBeNull();
		expect(
			decodeJobToken(Buffer.from('{"v":1,"kind":"other","paths":["/x"]}').toString("base64url")),
		).toBeNull();
		expect(
			decodeJobToken(Buffer.from('{"v":1,"kind":"md-batch","paths":[]}').toString("base64url")),
		).toBeNull();
		expect(decodeJobToken("A".repeat(5000))).toBeNull();
	});
});
